/**
 * Tạo kịch bản TikTok theo bộ (Campaign)
 * CƯỠNG ÉP ĐỘ DÀI: 160 - 190 ký tự.
 */
export const generateKocScript = async (
  imageParts: any[], productName: string, keyword: string, scriptTone: string,
  productSize: string, scriptNote: string, scriptLayout: string, gender: string, voice: string,
  sceneCount: number
): Promise<ScriptParts> => {
  const ai = getAiClient();

  let dialectInstruction = voice === 'Miền Bắc' 
    ? `VĂN PHONG MIỀN BẮC (HÀ NỘI): dùng luôn, ạ, thế, chứ.` 
    : `VĂN PHONG MIỀN NAM (SÀI GÒN): dùng lun, nè, thiệt, hông, vầy.`;

  const prompt = `
    Bạn là một Creator chuyên nghiệp, hãy tạo kịch bản bộ video viral (Campaign) gồm ${sceneCount} cảnh cho sản phẩm "${productName}". 
    USP chính: "${keyword}". 
    Bố cục yêu cầu: "${scriptLayout}". 
    Nhân vật: ${gender}, giọng ${voice}.

    YÊU CẦU NỘI DUNG:
    - Đúng ${sceneCount} phần (v1..v${sceneCount}). 
    - Các phần phải kết nối chặt chẽ thành một câu chuyện quảng cáo hoàn chỉnh từ Hook đến CTA.

    !!! QUAN TRỌNG NHẤT (STRICT LENGTH RULE) !!!:
    Mỗi phần kịch bản (v1, v2...) BẮT BUỘC PHẢI CÓ ĐỘ DÀI TỪ 160 ĐẾN 190 KÝ TỰ. 
    - Tuyệt đối KHÔNG ĐƯỢC NGẮN HƠN 160 ký tự.
    - Tuyệt đối KHÔNG ĐƯỢC DÀI HƠN 190 ký tự.
    ${dialectInstruction}
    - Kịch bản phải bắt đầu bằng một câu hỏi gây tò mò.

    QUY TẮC XƯNG HÔ (BẮT BUỘC):
     - Xưng là: "em"
     - Gọi người xem là: "anh chị" hoặc "các anh chị".

    !!! CẢNH BÁO TỪ CẤM !!!:
    ${FORBIDDEN_TERMS}
  `;

  const properties: Record<string, any> = {};
  const required: string[] = [];
  for (let i = 1; i <= sceneCount; i++) {
    const key = `v${i}`;
    properties[key] = { type: Type.STRING };
    required.push(key);
  }

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: [{ text: prompt }, ...imageParts.map(p => ({ inlineData: p }))] },
      config: {
        responseMimeType: "application/json",
        responseSchema: { type: Type.OBJECT, properties, required }
      }
    });
    return JSON.parse(cleanJsonResponse(response.text || '{}'));
  } catch (e) {
    const fallback: ScriptParts = {};
    for (let i = 1; i <= sceneCount; i++) fallback[`v${i}`] = '';
    return fallback;
  }
};

/**
 * Viết lại một phần kịch bản
 */
export const regenerateKocScriptPart = async (
  imageParts: any[], 
  productName: string, 
  keyword: string, 
  scriptPartKey: string,
  currentPartContent: string,
  fullScript: ScriptParts,
  gender: string, 
  voice: string,
  layout: string
): Promise<string> => {
  const ai = getAiClient();
  let dialectInstruction = voice === 'Miền Bắc' 
    ? `VĂN PHONG MIỀN BẮC (HÀ NỘI)` 
    : `VĂN PHONG MIỀN NAM (SÀI GÒN)`;

  const prompt = `
    Viết lại phần kịch bản "${scriptPartKey}" cho sản phẩm "${productName}".
    Nội dung cũ: "${currentPartContent}".
    Đảm bảo độ dài từ 160 đến 190 ký tự.
    TUYỆT ĐỐI KHÔNG dùng từ cấm: ${FORBIDDEN_TERMS}
    Giọng: ${voice}. ${dialectInstruction}. Xưng "em", gọi "anh chị".
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: [{ text: prompt }, ...imageParts.map(p => ({ inlineData: p }))] }
    });
    return response.text?.trim() || currentPartContent;
  } catch (error) {
    return currentPartContent;
  }
};

/**
 * Tạo hình ảnh với QUY TẮC BẢO MẬT KHUÔN MẶT TUYỆT ĐỐI.
 */
export const generateKocImage = async (
  referenceImageParts: any[], 
  faceImagePart: any | null, 
  outfitImagePart: any | null,
  outfitDescription: string, 
  productName: string,
  scriptPart: string, 
  characterDescription: string, 
  userCustomPrompt: string | undefined, 
  gender: string, 
  imageStyle: 'Realistic' | '3D' = 'Realistic', 
  backgroundNote: string = "",
  visualNote: string = "",
  poseLabel: string = "",
  backgroundReferencePart: any | null = null
): Promise<string> => {
  const ai = getAiClient();
  const is3D = imageStyle === '3D';

  const baseStyle = is3D 
    ? `High-quality 3D Animation Pixar/Disney style, vibrant but natural colors, polished CGI.`
    : `Photorealistic RAW PHOTO, natural lifestyle shot, 8k resolution, authentic skin textures, cinematic natural lighting.`;

  const noProductKeywords = ["không có sản phẩm", "xóa sản phẩm", "không xuất hiện sản phẩm", "bỏ sản phẩm", "không thấy sản phẩm", "no product", "remove product", "without product"];
  const isNoProductRequested = userCustomPrompt && noProductKeywords.some(kw => userCustomPrompt.toLowerCase().includes(kw));

  const identityRule = faceImagePart 
    ? `!!! MANDATORY IDENTITY RULE !!!: 
       - Transfer EXACT facial features, hair color, and hair style from the FACE_REFERENCE image. 
       - 1:1 match of the person's face.
       - !!! CRITICAL !!!: DO NOT use or look like any person found in the PRODUCT or OUTFIT reference images. ONLY use the face from FACE_REFERENCE.`
    : `IDENTITY: A unique adult Vietnamese ${gender} matching the character description: ${characterDescription}.`;

  const visualRules = `
    !!! STRICT VISUAL CONSTRAINTS !!!:
    1. ABSOLUTELY NO TEXT, NO LETTERS, NO NUMBERS, NO CHARACTERS.
    2. NO UI elements, NO icons, NO emojis, NO speech bubbles.
    3. NO CHILDREN, NO KIDS. Subject must be an adult.
    4. ASPECT RATIO: 9:16.

    STRICT CONTENT FIDELITY:
    - OUTFIT: Character must wear the outfit described as: "${outfitDescription}". 
    - !!! DISCARD OUTFIT FACE !!!: If there is a person in the OUTFIT reference image, COMPLETELY DISCARD their face and hair. ONLY use the clothing design.
    ${isNoProductRequested ? '3. ABSOLUTELY NO PRODUCT IN THIS IMAGE.' : `
    - PRODUCT FIDELITY: The product "${productName}" must match the PRODUCT reference images 1:1.
    - !!! DISCARD PRODUCT FACE !!!: If there is a person wearing the product in the reference images (Fashion product), COMPLETELY IGNORE their face, hair, and identity. ONLY extract the product design.`}
  `;

  const backgroundRule = backgroundReferencePart 
    ? `ENVIRONMENT: Use the exact background setting from BACKGROUND_REFERENCE.`
    : `ENVIRONMENT: Set in a natural ${backgroundNote || 'lifestyle setting'}.`;

  const poseInstruction = poseLabel ? `POSE (MANDATORY): ${poseLabel}.` : "";

  const prompt = `
    ${baseStyle} 
    ${identityRule}
    ${visualRules}
    ${backgroundRule}
    ${poseInstruction}
    ${visualNote ? `COMPOSITION: ${visualNote}.` : ""}
    SCENE: "${scriptPart}". 
    ${userCustomPrompt || ""}
  `;

  const contents: any[] = [{ text: prompt }];
  if (faceImagePart) contents.push({ inlineData: faceImagePart });
  if (outfitImagePart) contents.push({ inlineData: outfitImagePart });
  if (backgroundReferencePart) contents.push({ inlineData: backgroundReferencePart });
  if (!isNoProductRequested) referenceImageParts.forEach(part => contents.push({ inlineData: part }));

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: { parts: contents },
      config: { imageConfig: { aspectRatio: "9:16" } }
    });
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData?.data) return `data:image/png;base64,${part.inlineData.data}`;
    }
    throw new Error("Fail");
  } catch (error) { throw error; }
};

/**
 * Tạo Video Prompt cho VEO-3.
 */
export const generateKocVeoPrompt = async (
  productName: string, 
  scriptText: string, 
  gender: string, 
  voice: string,
  productImageBase64?: string,
  generatedImageBase64?: string,
  isNoProductRequested: boolean = false,
  imageStyle: 'Realistic' | '3D' = 'Realistic'
): Promise<string> => {
  const ai = getAiClient();
  const is3D = imageStyle === '3D';
  const voiceTag = voice === 'Miền Bắc' ? 'Northern Vietnamese' : 'Southern Vietnamese';
  const voiceGender = gender === 'Nữ' ? 'Female' : 'Male';

  const productInteractionRule = isNoProductRequested
    ? `PHẦN 2: HÀNH ĐỘNG: TUYỆT ĐỐI KHÔNG xuất hiện sản phẩm "${productName}". Nhân vật nói chuyện: "${scriptText}".`
    : `PHẦN 2: HÀNH ĐỘNG: Nhân vật đang cầm trên tay sản phẩm "${productName}". Sản phẩm giữ nguyên tỷ lệ 1:1, không biến dạng. Nhân vật nói chuyện: "${scriptText}".`;

  const instructionPrompt = `
  Nhiệm vụ: Viết video prompt Tiếng Anh chi tiết cho VEO-3 (8 giây).
  STYLE: ${is3D ? "3D Animation Pixar style" : "Photorealistic Life Style"}.

  CẤU TRÚC:
  1. Nhân vật & Diện mạo: Giữ nguyên khuôn mặt và kiểu tóc từ ảnh tham chiếu.
  2. ${productInteractionRule}
  3. Bối cảnh: Không gian sống hiện đại.
  4. Chuyển động: Zoom hoặc Dolly mượt mà (9:16).
  5. Lời thoại: ✨ Model speaks in ${voiceTag} voice (${voiceGender}): "${scriptText}"
  6. Tech: 4K, 60fps, No background music.

  YÊU CẦU: Trả về 1 dòng Tiếng Anh duy nhất.`;

  const contents: any[] = [{ text: instructionPrompt }];
  if (productImageBase64) contents.push({ inlineData: { mimeType: 'image/png', data: productImageBase64.split(',')[1] || productImageBase64 } });
  if (generatedImageBase64) contents.push({ inlineData: { mimeType: 'image/png', data: generatedImageBase64.split(',')[1] || generatedImageBase64 } });

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: contents }
    });
    return response.text?.trim().replace(/\n/g, ' ') || "";
  } catch (error) { return "Error generating video prompt."; }
};

