const KocReviewModule: React.FC = () => {
  const storageKey = "koc_project_v16_secure_faces";
  const [state, setState] = useState<any>({
    faceFile: null,
    facePreviewUrl: null,
    outfitFile: null,
    outfitPreviewUrl: null,
    outfitDescription: '',
    isExtractingOutfit: false,
    backgroundFile: null,
    backgroundPreviewUrl: null,
    characterDescription: '',
    gender: 'Nữ',
    voice: 'Miền Bắc',
    imageStyle: 'Realistic',
    sceneCount: 5,
    productFiles: [], 
    productPreviewUrls: [],
    productName: '',
    keyword: '',
    scriptTone: '',
    productSize: '',
    scriptNote: '', 
    visualNote: '',
    scriptLayout: '',
    isGeneratingScript: false,
    isRegeneratingPart: {},
    script: null,
    images: {},
    videoPrompts: {}
  });

  const productInputRef = useRef<HTMLInputElement>(null);
  const faceInputRef = useRef<HTMLInputElement>(null);
  const outfitInputRef = useRef<HTMLInputElement>(null);
  const backgroundInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    try {
      const saved = localStorage.getItem(storageKey);
      if (saved) {
        const parsed = JSON.parse(saved);
        if (parsed && typeof parsed === 'object') {
          setState((prev: any) => ({
            ...prev,
            ...parsed,
            productFiles: [],
            faceFile: null,
            outfitFile: null,
            backgroundFile: null,
            isGeneratingScript: false,
            isExtractingOutfit: false,
            isRegeneratingPart: {}
          }));
        }
      }
    } catch (e) { console.error("Failed to restore KOC state", e); }
  }, []);

  useEffect(() => {
    try {
      const { isGeneratingScript, isExtractingOutfit, isRegeneratingPart, productFiles, faceFile, outfitFile, backgroundFile, images, ...persistentData } = state;
      const safeImages = Object.keys(images || {}).reduce((acc: any, key) => {
        acc[key] = { ...images[key], url: '' };
        return acc;
      }, {});
      localStorage.setItem(storageKey, JSON.stringify({ ...persistentData, images: safeImages }));
    } catch (e) { console.error("Failed to save KOC state", e); }
  }, [state]);

  const handleProductFilesChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const selectedFiles = Array.from(e.target.files);
      const updatedFiles = [...state.productFiles, ...selectedFiles].slice(0, 3);
      const updatedUrls = updatedFiles.map(f => URL.createObjectURL(f));
      setState((prev: any) => ({
        ...prev,
        productFiles: updatedFiles,
        productPreviewUrls: updatedUrls
      }));
    }
    if (productInputRef.current) productInputRef.current.value = "";
  };

  const removeProductFile = (idx: number) => {
    const updatedFiles = state.productFiles.filter((_: any, i: number) => i !== idx);
    const updatedPreviewUrls = state.productPreviewUrls.filter((_: any, i: number) => i !== idx);
    setState((prev: any) => ({
      ...prev,
      productFiles: updatedFiles,
      productPreviewUrls: updatedPreviewUrls
    }));
  };

  const handleFaceFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setState((prev: any) => ({
        ...prev,
        faceFile: file,
        facePreviewUrl: URL.createObjectURL(file)
      }));
    }
  };

  const handleOutfitFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setState((prev: any) => ({
        ...prev,
        outfitFile: file,
        outfitPreviewUrl: URL.createObjectURL(file),
        outfitDescription: ''
      }));
    }
  };

  const handleBackgroundFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setState((prev: any) => ({
        ...prev,
        backgroundFile: file,
        backgroundPreviewUrl: URL.createObjectURL(file)
      }));
    }
  };

  const handleExtractOutfit = async () => {
    let part = null;
    if (state.outfitFile) {
        part = await service.fileToGenerativePart(state.outfitFile);
    } else if (state.outfitPreviewUrl?.startsWith('data:')) {
        part = { mimeType: 'image/png', data: state.outfitPreviewUrl.split(',')[1] };
    }

    if (!part) return;
    setState(p => ({ ...p, isExtractingOutfit: true }));
    try {
      const desc = await service.describeKocOutfit(part);
      setState(p => ({ ...p, outfitDescription: desc, isExtractingOutfit: false }));
    } catch (e) {
      console.error(e);
      setState(p => ({ ...p, isExtractingOutfit: false }));
    }
  };

  const handleGenerate = async () => {
    if (state.productFiles.length === 0 && state.productPreviewUrls.length === 0) {
      alert("Vui lòng tải ảnh sản phẩm.");
      return;
    }
    if (!state.productName) {
      alert("Vui lòng nhập tên sản phẩm.");
      return;
    }

    const activeKeys = Array.from({ length: state.sceneCount }, (_, i) => `v${i + 1}`);
    const initialImages: any = {};
    const initialPrompts: any = {};
    activeKeys.forEach(k => {
      initialImages[k] = { url: '', loading: false, customPrompt: '', pose: '' };
      initialPrompts[k] = { text: '', loading: false, visible: false };
    });

    setState((prev: any) => ({
      ...prev,
      isGeneratingScript: true,
      script: null,
      images: initialImages,
      videoPrompts: initialPrompts
    }));

    try {
      let imageParts = [];
      if (state.productFiles.length > 0) {
        imageParts = await Promise.all(state.productFiles.map((file: File) => service.fileToGenerativePart(file)));
      } else {
        imageParts = state.productPreviewUrls.map((url: string) => ({
          mimeType: 'image/png',
          data: url.split(',')[1]
        }));
      }

      let layoutToUse = state.scriptLayout;
      if (!layoutToUse) layoutToUse = LAYOUT_OPTIONS[Math.floor(Math.random() * LAYOUT_OPTIONS.length)];

      const script = await service.generateKocScript(
        imageParts,
        state.productName,
        state.keyword,
        state.scriptTone,
        state.productSize,
        state.scriptNote,
        layoutToUse,
        state.gender,
        state.voice,
        state.sceneCount
      );
      setState((prev: any) => ({ ...prev, script, scriptLayout: layoutToUse }));
    } catch (e) {
      console.error(e);
    } finally {
      setState((prev: any) => ({ ...prev, isGeneratingScript: false }));
    }
  };

  const handleRegenerateScriptPart = async (key: string) => {
    if (state.isGeneratingScript || state.isRegeneratingPart[key] || !state.script) return;
    setState((p: any) => ({ ...p, isRegeneratingPart: { ...p.isRegeneratingPart, [key]: true } }));
    try {
      let imageParts = [];
      if (state.productFiles.length > 0) {
        imageParts = await Promise.all(state.productFiles.map((file: File) => service.fileToGenerativePart(file)));
      } else {
        imageParts = state.productPreviewUrls.map((url: string) => ({ mimeType: 'image/png', data: url.split(',')[1] }));
      }
      const newPartContent = await service.regenerateKocScriptPart(
        imageParts, state.productName, state.keyword, key, state.script[key], state.script, state.gender, state.voice, state.scriptLayout
      );
      setState((p: any) => ({
        ...p,
        script: { ...p.script, [key]: newPartContent },
        isRegeneratingPart: { ...p.isRegeneratingPart, [key]: false }
      }));
    } catch (error) {
      setState((p: any) => ({ ...p, isRegeneratingPart: { ...p.isRegeneratingPart, [key]: false } }));
    }
  };

  const handleGenImageForKey = async (key: string) => {
    setState((prev: any) => ({ ...prev, images: { ...prev.images, [key]: { ...prev.images[key], loading: true } } }));
    try {
      let productParts = [];
      if (state.productFiles.length > 0) {
        productParts = await Promise.all(state.productFiles.map((file: File) => service.fileToGenerativePart(file)));
      } else {
        productParts = state.productPreviewUrls.map((url: string) => ({ mimeType: 'image/png', data: url.split(',')[1] }));
      }

      const getPart = async (file: File | null, url: string | null) => {
        if (file) return await service.fileToGenerativePart(file);
        if (url?.startsWith('data:')) return { mimeType: 'image/png', data: url.split(',')[1] };
        return null;
      };

      const facePart = await getPart(state.faceFile, state.facePreviewUrl);
      const outfitPart = await getPart(state.outfitFile, state.outfitPreviewUrl);
      const bgRefPart = await getPart(state.backgroundFile, state.backgroundPreviewUrl);

      const poseLabel = KOC_POSES.find(p => p.value === state.images[key]?.pose)?.label || "";

      const url = await service.generateKocImage(
        productParts, facePart, outfitPart, state.outfitDescription, state.productName,
        state.script[key], state.characterDescription, state.images[key]?.customPrompt,
        state.gender, state.imageStyle, state.scriptNote, state.visualNote, poseLabel, bgRefPart
      );
      setState((prev: any) => ({ ...prev, images: { ...prev.images, [key]: { ...prev.images[key], url, loading: false } } }));
    } catch (e) {
      setState((prev: any) => ({ ...prev, images: { ...prev.images, [key]: { ...prev.images[key], loading: false, error: 'Failed' } } }));
    }
  };

  const handleBulkImage = async () => {
    const keys = Array.from({ length: state.sceneCount }, (_, i) => `v${i + 1}`);
    for (const key of keys) await handleGenImageForKey(key);
  };

  const handleGeneratePromptForKey = async (key: string) => {
    setState(p => ({ ...p, videoPrompts: { ...p.videoPrompts, [key]: { ...p.videoPrompts[key], loading: true, visible: true } } }));
    try {
      let productImageData = "";
      if (state.productFiles.length > 0) {
        const p = await service.fileToGenerativePart(state.productFiles[0]);
        productImageData = p.data;
      } else if (state.productPreviewUrls.length > 0) {
        productImageData = state.productPreviewUrls[0].split(',')[1];
      }
      const prompt = await service.generateKocVeoPrompt(
        state.productName, state.script[key], state.gender, state.voice, productImageData, state.images[key].url, false, state.imageStyle
      );
      setState(p => ({ ...p, videoPrompts: { ...p.videoPrompts, [key]: { text: prompt, loading: false, visible: true } } }));
    } catch (e) {
      setState(p => ({ ...p, videoPrompts: { ...p.videoPrompts, [key]: { ...p.videoPrompts[key], loading: false } } }));
    }
  };

  const handleBulkPrompt = async () => {
    const keys = Array.from({ length: state.sceneCount }, (_, i) => `v${i + 1}`);
    for (const key of keys) await handleGeneratePromptForKey(key);
  };

  const downloadAllImages = async () => {
    if (typeof JSZip === 'undefined') return alert("Loading ZIP library...");
    const zip = new JSZip();
    const activeKeys = Array.from({ length: state.sceneCount }, (_, i) => `v${i + 1}`);
    let count = 0;
    for (let i = 0; i < activeKeys.length; i++) {
      const img = state.images[activeKeys[i]];
      if (img?.url) { zip.file(`${String(i + 1).padStart(2, '0')}.png`, img.url.split(',')[1], { base64: true }); count++; }
    }
    if (count === 0) return alert("No images.");
    const content = await zip.generateAsync({ type: "blob" });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(content);
    link.download = `koc_${state.productName || 'project'}.zip`;
    link.click();
  };

  const hasGeneratedItems = state.script && Object.values(state.images).some((img: any) => img.url);

  return (
    <div className="max-w-7xl mx-auto px-4 py-8">
      {/* Alert Banner for Privacy */}
      <div className="mb-6 bg-indigo-50 border-l-4 border-indigo-500 p-4 rounded-r-xl flex items-center gap-3">
        <div className="p-2 bg-indigo-100 rounded-full text-indigo-600">
           <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" /></svg>
        </div>
        <div>
          <p className="text-xs font-black text-indigo-900 uppercase tracking-tight">Cơ chế Bảo mật Danh tính (Identity Shield)</p>
          <p className="text-[10px] text-indigo-700 font-medium">Hệ thống đã được lập trình để TUYỆT ĐỐI không sử dụng khuôn mặt từ ảnh trang phục hoặc ảnh sản phẩm vào kết quả cuối cùng.</p>
        </div>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6 mb-8">
        <div className="grid grid-cols-1 md:grid-cols-12 gap-8">
          <div className="md:col-span-5 flex flex-col gap-4">
            <div className="space-y-3">
              <label className="block text-sm font-bold text-slate-700">1. Hình ảnh sản phẩm (Tối đa 3)</label>
              <div 
                onClick={() => productInputRef.current?.click()} 
                className="w-full h-32 rounded-xl border-2 border-dashed border-slate-300 flex flex-col items-center justify-center cursor-pointer bg-slate-50 hover:bg-slate-100 transition-all group"
              >
                <div className="flex flex-col items-center opacity-40 group-hover:opacity-60 transition-opacity">
                  <svg className="w-8 h-8 text-orange-500 mb-1" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
                  <span className="text-[10px] font-black uppercase tracking-widest">Tải ảnh sản phẩm</span>
                </div>
                <input type="file" multiple ref={productInputRef} onChange={handleProductFilesChange} className="hidden" accept="image/*" />
              </div>

              {state.productPreviewUrls.length > 0 && (
                <div className="grid grid-cols-3 gap-3 pt-1">
                  {state.productPreviewUrls.map((url: string, idx: number) => (
                    <div key={idx} className="relative aspect-[3/4] rounded-lg overflow-hidden border border-slate-200 group/item shadow-sm">
                      <img src={url} className="w-full h-full object-cover" />
                      <button onClick={() => removeProductFile(idx)} className="absolute top-1 right-1 bg-black/50 hover:bg-red-600 text-white p-1 rounded-full opacity-0 group-item/item:opacity-100 transition-opacity"><svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M6 18L18 6M6 6l12 12" /></svg></button>
                    </div>
                  ))}
                </div>
              )}
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <label className="block text-sm font-bold text-slate-700">0. Ảnh mặt mẫu</label>
                <div onClick={() => faceInputRef.current?.click()} className="relative w-full aspect-square rounded-xl border-2 border-dashed border-slate-300 flex items-center justify-center cursor-pointer bg-slate-50 hover:bg-slate-100 overflow-hidden">
                  {state.facePreviewUrl ? <img src={state.facePreviewUrl} className="h-full object-cover" /> : <span className="text-slate-400 text-[10px] uppercase font-bold text-center p-2">Ảnh mặt</span>}
                  <input type="file" ref={faceInputRef} onChange={handleFaceFileChange} className="hidden" accept="image/*" />
                </div>
              </div>
              <div className="space-y-2">
                <label className="block text-sm font-bold text-slate-700">2. Ảnh trang phục</label>
                <div onClick={() => outfitInputRef.current?.click()} className="relative w-full aspect-square rounded-xl border-2 border-dashed border-slate-300 flex items-center justify-center cursor-pointer bg-slate-50 hover:bg-slate-100 overflow-hidden">
                  {state.outfitPreviewUrl ? <img src={state.outfitPreviewUrl} className="h-full object-cover" /> : <span className="text-slate-400 text-[10px] uppercase font-bold text-center p-2">Trang phục</span>}
                  <input type="file" ref={outfitInputRef} onChange={handleOutfitFileChange} className="hidden" accept="image/*" />
                </div>
                {(state.outfitFile || state.outfitPreviewUrl?.startsWith('data:')) && (
                  <button onClick={handleExtractOutfit} disabled={state.isExtractingOutfit} className={`w-full py-2 rounded-lg text-[10px] font-black uppercase transition-all shadow-sm ${state.outfitDescription ? 'bg-green-100 text-green-700 border border-green-200' : 'bg-blue-600 text-white hover:bg-blue-700'}`}>
                    {state.isExtractingOutfit ? "..." : state.outfitDescription ? "Đã tách ✓" : "Tách kiểu dáng"}
                  </button>
                )}
              </div>
            </div>

            {state.outfitDescription && (
              <div className="p-3 bg-green-50/50 border border-green-100 rounded-xl">
                <p className="text-[9px] font-black text-green-600 uppercase mb-1">Dáng trang phục (AI focus):</p>
                <p className="text-[10px] text-green-800 italic leading-relaxed line-clamp-2">"{state.outfitDescription}"</p>
              </div>
            )}
          </div>

          <div className="md:col-span-7 space-y-4">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-1">
                <label className="block text-[10px] font-bold text-slate-500 uppercase px-1">Tên sản phẩm</label>
                <input type="text" value={state.productName} onChange={e => setState(p => ({ ...p, productName: e.target.value }))} placeholder="Nhập tên sản phẩm..." className="w-full p-3 border rounded-xl focus:ring-2 focus:ring-orange-100 outline-none transition-all font-bold" />
              </div>
              <div className="space-y-1">
                <label className="block text-[10px] font-bold text-slate-500 uppercase px-1">Thời lượng (Scenes)</label>
                <select value={state.sceneCount} onChange={e => setState(p => ({ ...p, sceneCount: parseInt(e.target.value) }))} className="w-full p-3 border rounded-xl bg-white focus:ring-2 focus:ring-orange-100 outline-none font-bold text-orange-600">
                  {SCENE_COUNT_OPTIONS.map(opt => <option key={opt.count} value={opt.count}>{opt.label}</option>)}
                </select>
              </div>
            </div>

            <div className="space-y-1">
              <label className="block text-[10px] font-bold text-slate-500 uppercase px-1">USP sản phẩm</label>
              <textarea value={state.keyword} onChange={e => setState(p => ({ ...p, keyword: e.target.value }))} placeholder="Công dụng, giá trị nổi bật..." className="w-full p-3 border rounded-xl h-20 text-sm focus:ring-2 focus:ring-orange-100 outline-none" />
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-1">
                <label className="block text-[10px] font-bold text-slate-500 uppercase px-1">Giới tính</label>
                <select value={state.gender} onChange={e => setState(p => ({ ...p, gender: e.target.value }))} className="w-full p-3 border rounded-xl bg-white outline-none"><option value="Nữ">Nữ</option><option value="Nam">Nam</option></select>
              </div>
              <div className="space-y-1">
                <label className="block text-[10px] font-bold text-slate-500 uppercase px-1">Vùng miền</label>
                <select value={state.voice} onChange={e => setState(p => ({ ...p, voice: e.target.value }))} className="w-full p-3 border rounded-xl bg-white outline-none"><option value="Miền Bắc">Miền Bắc</option><option value="Miền Nam">Miền Nam</option></select>
              </div>
            </div>

            <div className="space-y-1">
              <label className="block text-[10px] font-bold text-slate-500 uppercase px-1">Bố cục kịch bản</label>
              <select value={state.scriptLayout} onChange={e => setState(p => ({ ...p, scriptLayout: e.target.value }))} className="w-full p-3 border rounded-xl bg-white outline-none">
                <option value="">-- Random Layout --</option>
                {LAYOUT_OPTIONS.map(o => <option key={o} value={o}>{o}</option>)}
              </select>
            </div>

            <button onClick={handleGenerate} disabled={state.isGeneratingScript} className="w-full py-4 bg-orange-600 text-white font-black rounded-xl shadow-lg hover:bg-orange-700 transition-all active:scale-[0.98] uppercase tracking-widest">
              {state.isGeneratingScript ? "ĐANG TẠO KỊCH BẢN BỘ..." : "BẮT ĐẦU TẠO CAMPAIGN"}
            </button>
          </div>
        </div>
      </div>

      {state.script && (
        <div className="space-y-8 pb-32 animate-fadeIn">
          <div className="bg-slate-900 p-6 rounded-2xl border border-slate-800 shadow-sm">
            <h3 className="text-sm font-black text-white uppercase tracking-tight">KẾT QUẢ CHIẾN DỊCH KOC</h3>
            <p className="text-[10px] font-bold text-orange-500 uppercase tracking-widest">
              {state.sceneCount} cảnh ({state.sceneCount * 8}s) • {state.imageStyle} Style • Identity Shield Active
            </p>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-5 gap-6">
            {Array.from({ length: state.sceneCount }, (_, i) => `v${i + 1}`).map((key, idx) => (
              <div key={key} className="space-y-4">
                <ScriptSection
                  title={`Cảnh ${idx + 1}`}
                  content={state.script[key]}
                  color="border-orange-500"
                  onChange={(val) => setState(p => ({ ...p, script: { ...p.script, [key]: val } }))}
                  onRegenerate={() => handleRegenerateScriptPart(key)}
                  isRegenerating={state.isRegeneratingPart[key]}
                />
                <ImageCard
                  label={`Visual ${idx + 1}`}
                  imageData={state.images[key]}
                  videoPrompt={state.videoPrompts[key]}
                  onGeneratePrompt={() => handleGeneratePromptForKey(key)}
                  onRegenerate={() => handleGenImageForKey(key)}
                  onTranslate={() => { }}
                  pose={state.images[key]?.pose || ''}
                  onPoseChange={(val) => setState(p => ({ ...p, images: { ...p.images, [key]: { ...p.images[key], pose: val } } }))}
                  customPrompt={state.images[key]?.customPrompt || ''}
                  onCustomPromptChange={(val) => setState(p => ({ ...p, images: { ...p.images, [key]: { ...p.images[key], customPrompt: val } } }))}
                />
              </div>
            ))}
          </div>

          <div className="flex flex-col items-center gap-4 py-12">
            <div className="flex flex-col md:flex-row gap-4 w-full justify-center">
              <button onClick={handleBulkImage} className="px-12 py-5 bg-orange-600 text-white font-black rounded-2xl shadow-xl hover:scale-105 active:scale-95 transition-all text-lg uppercase">TẠO TẤT CẢ ẢNH</button>
              <button onClick={handleBulkPrompt} className="px-12 py-5 bg-slate-900 text-white font-black rounded-2xl shadow-xl hover:scale-105 active:scale-95 transition-all text-lg uppercase">TẠO TẤT CẢ PROMPTS</button>
            </div>
            {hasGeneratedItems && (
              <button onClick={downloadAllImages} className="mt-4 px-12 py-4 bg-slate-100 text-slate-600 font-black rounded-xl hover:bg-slate-200 transition-all uppercase text-sm tracking-widest">TẢI BỘ ẢNH (ZIP)</button>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default KocReviewModule;

